```
import * as Excel from 'exceljs';
exportExcel(){
    var workbook = new Excel.Workbook();
    var worksheet = workbook.addWorksheet('Log');
    worksheet.columns = [
      { header: "IP Number", key: 'ip_address', width: 10 },
      { header: "Actor", key: 'actor_type', width: 10 },
